#ifndef ESEC_CERT_BASICS_HEADER
#define ESEC_CERT_BASICS_HEADER

#include <stdint.h>
#include <stddef.h>
#include "esec_ed25519.h"
#include "esec_ecc.h"

#define ESEC_AUTH_ALGO_ECDSA_P256 1
#define ESEC_AUTH_ALGO_ECDSA_P384 2
#define ESEC_AUTH_ALGO_ECDSA_P521 3
#define ESEC_AUTH_ALGO_ED25519    4
#define ESEC_AUTH_ALGO_RSA_4K     5

#if ESEC_AUTH_ALGO == ESEC_AUTH_ALGO_ED25519
#define ESEC_MFCT_PUBKEY_SZ 32
#define ESEC_MFCT_SIG_SZ    64
#define ESEC_MFCT_KEY_PAIR  (ESEC_MFCT_PUBKEY_SZ * 2)
typedef struct esec_eddsa_key esec_certifier_key;
#elif ESEC_AUTH_ALGO == ESEC_AUTH_ALGO_ECDSA_P256
#define ESEC_MFCT_PUBKEY_SZ (32 * 2)
#define ESEC_MFCT_SIG_SZ    (32 * 2)
#define ESEC_MFCT_KEY_PAIR  (ESEC_MFCT_PUBKEY_SZ + ESEC_MFCT_PUBKEY_SZ / 2)
typedef struct esec_ecc_key esec_certifier_key;
#elif ESEC_AUTH_ALGO == ESEC_AUTH_ALGO_ECDSA_P384
#define ESEC_MFCT_PUBKEY_SZ (48 * 2)
#define ESEC_MFCT_SIG_SZ    (48 * 2)
#define ESEC_MFCT_KEY_PAIR  (ESEC_MFCT_PUBKEY_SZ + ESEC_MFCT_PUBKEY_SZ / 2)
typedef struct esec_ecc_key esec_certifier_key;
#elif ESEC_AUTH_ALGO == ESEC_AUTH_ALGO_ECDSA_P521
#define ESEC_MFCT_PUBKEY_SZ (66 * 2)
#define ESEC_MFCT_SIG_SZ    (66 * 2)
#define ESEC_MFCT_KEY_PAIR  (ESEC_MFCT_PUBKEY_SZ + ESEC_MFCT_PUBKEY_SZ / 2)
typedef struct esec_ecc_key esec_certifier_key;
#elif ESEC_AUTH_ALGO == ESEC_AUTH_ALGO_RSA_4K
#define ESEC_MFCT_PUBKEY_SZ (512 + 4)
#define ESEC_MFCT_SIG_SZ    (512)
#define ESEC_MFCT_KEY_PAIR  (512 + 4 + 256 * 5)
typedef struct esec_rsa_key esec_certifier_key;
#else
#error "FATAL ERROR: unsupported authentication algorithm"
#endif

#if ESEC_PUBKEY_HASH_ALGO == ESEC_HASH_ALGO_SHA256
#define ESEC_PUBKEY_DIGESTSIZE ESEC_HASH_SIZE_SHA256
#elif ESEC_PUBKEY_HASH_ALGO == ESEC_HASH_ALGO_SHA384
#define ESEC_PUBKEY_DIGESTSIZE ESEC_HASH_SIZE_SHA384
#elif ESEC_PUBKEY_HASH_ALGO == ESEC_HASH_ALGO_SHA512
#define ESEC_PUBKEY_DIGESTSIZE ESEC_HASH_SIZE_SHA512
#else
#error "FATAL ERROR: unsupported eSecure pubkey hash algorithm."
#endif

/** eSecure certificate of a ED25519 key **/
struct __attribute__((__packed__)) esec_cert_ed25519_key {
    /** Magic number which should always be 0xE5ECA101 **/
    uint32_t magic;
    /** Nonce **/
    uint8_t nonce[12];
    /** Key metadata **/
    uint32_t signed_key_metadata;
    /** Signed (public) key **/
    uint8_t signed_key[32];
    /** Signature of this certificate **/
    uint8_t signature[ESEC_MFCT_SIG_SZ];
};

/** eSecure certificate of the current RTC time. **/
struct __attribute__((__packed__)) esec_time_certificate {
    /** Magic number which should always be 0xE5ECA201 **/
    uint32_t magic;
    /** Qualifying data provided by the host, useally a nonce. **/
    uint8_t nonce[12];
    /** Current RTC value **/
    uint64_t time;
    /** Signature of this certificate **/
    uint8_t signature[ESEC_MFCT_SIG_SZ];
};

/** Chip public EK certificate signed by the chip manufacturer **/
struct __attribute__((__packed__)) esec_chip_certificate {
    /** Magic number which should always be 0xE5ECCC01 **/
    uint32_t magic;
    /** Serial number **/
    uint8_t serial[16];
    /** Public part of the endorsement key (EK) built in the chip **/
    uint8_t endorsement_pubkey[ESEC_MFCT_PUBKEY_SZ];
    /** Signature of this certificate **/
    uint8_t signature[ESEC_MFCT_SIG_SZ];
};

/** Base size of a key certificate generated by eSecure.
 *
 * For the full size of the key certificate, one needs to add the size of the
 * key public and when applicable the size of the domain parameters.
 **/
#define ESEC_CERT_KEY_BASE_SIZE (4 + 12 + 4 + ESEC_MFCT_SIG_SZ)

#endif
